const texto = $('nova_tarefa').first().json.task_name;
const data = $('nova_tarefa').first().json.date;
const hora = $('nova_tarefa').first().json.time;

const d = new Date(data + "T00:00:00");
const hoje = new Date();

hoje.setHours(0,0,0,0);

const diff = Math.round((d - hoje) / 86400000);

let dia;

// hoje / amanhã
if (diff === 0) dia = "hoje";
else if (diff === 1) dia = "amanhã";

// até 7 dias → nome do dia
else if (diff <= 7) {
  dia = d.toLocaleDateString('pt-BR', { weekday: 'long' });
}

// mais distante → dd/mm
else {
  dia = d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
}

let msg;

if (hora) {
  const [h, m] = hora.split(':');
  const horaFormatada = m === '00' ? `${h}h` : `${h}h${m}`;
  msg = `Anotado: ${texto} ${dia} às ${horaFormatada}`;
} else {
  msg = `Anotado: ${texto} ${dia}`;
}

return [{ msg }];

const texto = $('DimiEditor').first().json.output.task_name;
const status = $('DimiEditor').first().json.output.status;
const data = $('DimiEditor').first().json.output.data;
const hora = $('DimiEditor').first().json.output.hora;

let msg;

// ===== concluir =====
if (status === "Concluída") {
  msg = `Marquei ${texto} como concluída.`;
}

// ===== cancelar =====
else if (status === "Cancelada") {
  msg = `Cancelei ${texto}.`;
}

// ===== formatar data (se existir) =====
let dia = null;

if (data) {
  const d = new Date(data + "T00:00:00");
  const hoje = new Date();
  hoje.setHours(0,0,0,0);

  const diff = Math.round((d - hoje) / 86400000);

  if (diff === 0) dia = "hoje";
  else if (diff === 1) dia = "amanhã";
  else if (diff <= 7) dia = d.toLocaleDateString('pt-BR', { weekday: 'long' });
  else dia = d.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
}

// ===== formatar hora (se existir) =====
let horaFormatada = null;

if (hora) {
  const [h, m] = hora.split(':');
  horaFormatada = m === '00' ? `${h}h` : `${h}h${m}`;
}

// ===== remarcar casos =====
if (!msg) {
  if (dia && horaFormatada) {
    msg = `Remarquei ${texto} para ${dia} às ${horaFormatada}.`;
  }
  else if (dia) {
    msg = `Remarquei ${texto} para ${dia}.`;
  }
  else if (horaFormatada) {
    msg = `Atualizei ${texto} para ${horaFormatada}.`;
  }
  else {
    msg = `Atualizei ${texto}.`;
  }
}

return [{ msg }];

